-- Cria itens das ordens antigas que tinham produto direto na tabela principal.
SELECT o.id,o.produto_id,o.quantidade,o.preco_negociado,o.frete,o.valor_total,o.tipo_material,p.unidade,p.quantidade_por_unidade_compra,p.unidade_base
FROM ordens_compra o
JOIN produtos p ON p.id=o.produto_id
WHERE o.produto_id IS NOT NULL
  AND NOT EXISTS (SELECT 1 FROM ordem_compra_itens i WHERE i.ordem_id=o.id);

SELECT setval(pg_get_serial_sequence('fornecedores','id'), COALESCE((SELECT MAX(id) FROM fornecedores), 1), true);
SELECT setval(pg_get_serial_sequence('unidades_medida','id'), COALESCE((SELECT MAX(id) FROM unidades_medida), 1), true);
SELECT setval(pg_get_serial_sequence('cadastro_categorias','id'), COALESCE((SELECT MAX(id) FROM cadastro_categorias), 1), true);
