SELECT setval(pg_get_serial_sequence('produtos','id'), COALESCE((SELECT MAX(id) FROM produtos), 1), true);
SELECT setval(pg_get_serial_sequence('ordens_compra','id'), COALESCE((SELECT MAX(id) FROM ordens_compra), 1), true);
SELECT setval(pg_get_serial_sequence('autorizacoes','id'), COALESCE((SELECT MAX(id) FROM autorizacoes), 1), true);
SELECT setval(pg_get_serial_sequence('recebimentos','id'), COALESCE((SELECT MAX(id) FROM recebimentos), 1), true);
